#include <bits/stdc++.h> 
using namespace std;
const int N=200005;
int t,n,kk,q,dp[105][N];
vector<int> v[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--)
	{
		memset(dp,-1,sizeof(dp));
		cin>>n>>kk>>q;
		for(int i=1;i<=n;i++) 
		{
			v[i].clear();
			int len;
			cin>>len;
			for(int j=1;j<=len;j++)
			{
				int x;
				cin>>x;
				v[i].push_back(x);
			}
		}
		dp[0][1]=0;
		for(int i=1;i<=100;i++)
		{
			for(int j=1;j<=n;j++)
			{
				int flag=0;
				for(int k=0;k<v[j].size();k++)
				{
					int t=v[j][k];
					flag--;
					if(flag>0)
					{
						dp[i][t]=(dp[i][t]==-1)?j:((dp[i][t]!=0&&dp[i][t]!=j)?0:dp[i][t]);
					}
					if((dp[i-1][t]>=0)&&(dp[i-1][t]!=j))
					{
						flag=kk;
//						cout<<"aa  ";
					}
//					cout<<"len  : "<<i<<"  "<<j<<"  "<<t<<"  flag : "<<flag<<"  dp : "<<dp[i][t]<<"  dp i-1 t : "<<dp[i-1][t]<<"\n";
				}
			}
		}
		while(q--)
		{
			int x,y;
			cin>>x>>y;
			string s="01";
			cout<<s[(dp[x][y]>=0)]<<"\n";
		}
	}
	return 0;
}
